// Public-facing worker
addEventListener("fetch", event => {
  const url = new URL(event.request.url);
  const pathname = url.pathname;

  // Forward requests to internal workers based on the pathname
  if (pathname === "/api/internal1") {
    return forwardToInternalWorker("internal1", event);
  } else if (pathname === "/api/internal2") {
    return forwardToInternalWorker("internal2", event);
  } else {
    // Return a 404 response if the pathname is not recognized
    return new Response("Not found", { status: 404 });
  }
});

// Forward requests to internal workers
function forwardToInternalWorker(workerName, event) {
  const worker = CloudflareWorkers.getWorker(workerName);
  if (!worker) {
    return new Response("Internal worker not found", { status: 500 });
  }

  // Create a new request with the original headers and body
  const request = new Request(event.request, {
    headers: event.request.headers,
    body: event.request.body,
  });

  // Forward the request to the internal worker
  return fetch(worker, request);
}